import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import HeroSpotlight from './components/HeroSpotlight';
import ActivityTicker from './components/ActivityTicker';
import AuthUI from './components/AuthUI';
import { Search, Cpu, Loader2, Terminal, LayoutGrid, Book, Gamepad2, Settings } from 'lucide-react';
import sql from './lib/neon';

const App: React.FC = () => {
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [allModules, setAllModules] = useState<AppItem[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const staticModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const initIdentity = async () => {
      let identity = null;
      const saved = localStorage.getItem('zst_identity');

      if (saved) {
        identity = JSON.parse(saved);
      } else {
        const randomId = Math.random().toString(16).slice(2, 6).toUpperCase();
        identity = { email: `GUEST-${randomId}@zst.local` };
        localStorage.setItem('zst_identity', JSON.stringify(identity));
      }

      setUser(identity);

      if (sql && identity) {
        try {
          await sql`
            INSERT INTO portal_users (email) 
            VALUES (${identity.email}) 
            ON CONFLICT (email) DO NOTHING
          `;
        } catch (e) {
          console.warn("[Identity Sync] Offline or DB unavailable");
        }
      }
    };

    initIdentity();
    setAllModules(staticModules);
    setIsLoading(false);
  }, []);

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 1200);
  };

  const categories = [
    { id: 'ALL', label: '全部', icon: LayoutGrid },
    { id: 'EDUCATION', label: '知识', icon: Book },
    { id: 'ENTERTAINMENT', label: '娱乐', icon: Gamepad2 },
    { id: 'UTILITIES', label: '工具', icon: Settings },
  ];

  if (isBooting) {
    return (
      <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6">
        <div className="relative">
          <div className="w-20 h-20 md:w-24 md:h-24 bg-emerald-500 clip-tech-border flex items-center justify-center animate-pulse shadow-[0_0_50px_rgba(16,185,129,0.3)]">
            <Cpu className="w-10 h-10 md:w-12 md:h-12 text-black animate-spin" />
          </div>
        </div>
        <h2 className="mt-8 text-center text-lg md:text-xl font-black tech-font text-white italic tracking-widest uppercase">
          初始化链路: {bootingAppTitle}
        </h2>
        <div className="mt-6 w-48 h-1 bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 animate-[loading_1.2s_linear_infinite]"></div>
        </div>
      </div>
    );
  }

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return (
        <div className="min-h-screen bg-black flex flex-col items-center justify-center text-center p-6">
          <Terminal className="w-12 h-12 text-emerald-500 mb-4 opacity-50" />
          <h1 className="text-xl font-bold text-white mb-2 tech-font uppercase">系统待机模式</h1>
          <p className="text-slate-500 mb-8 font-mono text-[10px] tracking-widest uppercase">ID: {runningAppId} / IN_DEV</p>
          <button onClick={() => setRunningAppId(null)} className="w-full max-w-xs py-4 border border-red-500/50 text-red-500 font-black tracking-[0.2em] uppercase italic clip-button hover:bg-red-500/10 transition-colors active:scale-95">终止进程</button>
        </div>
      );
    }
  };

  if (runningAppId) return renderApp();

  return (
    <div className="min-h-screen bg-[#020617] text-slate-300 pb-24 md:pb-20">
      <nav className="sticky top-0 z-40 bg-slate-950/80 backdrop-blur-md border-b border-slate-900/50 pt-[env(safe-area-inset-top)]">
        <div className="max-w-7xl mx-auto px-4 md:px-6 h-16 md:h-20 flex justify-between items-center">
          <div className="flex items-center gap-2 md:gap-4 cursor-pointer group" onClick={() => setActiveCategory('ALL')}>
            <div className="w-8 h-8 md:w-10 md:h-10 bg-emerald-500 flex items-center justify-center clip-button group-hover:rotate-12 transition-transform">
              <Cpu className="text-black w-5 h-5 md:w-6 md:h-6" />
            </div>
            <span className="text-lg md:text-2xl font-black italic tech-font text-white tracking-tighter uppercase truncate max-w-[120px] md:max-w-none group-hover:text-emerald-400 transition-colors">知识通</span>
          </div>

          <div className="flex items-center gap-3 md:gap-6">
            <div className="relative group hidden md:block">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-emerald-500 transition-colors" />
              <input 
                type="text" placeholder="搜索模块..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-12 pr-6 py-2.5 bg-slate-900 border border-slate-800 text-xs font-mono focus:outline-none focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 w-32 transition-all focus:w-64 rounded-xl"
              />
            </div>
            <AuthUI user={user} />
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 md:px-6 py-6 md:py-10">
        {!searchQuery && activeCategory === 'ALL' && allModules.length > 0 && (
          <HeroSpotlight item={allModules.find(m => m.id === 'e20') || allModules[0]} onRun={handleRunApp} />
        )}

        <div className="flex flex-col gap-6 mb-10 md:mb-12 border-b border-slate-900 pb-6 md:pb-8">
          <div className="flex items-center gap-3">
             <LayoutGrid className="text-emerald-500 w-4 h-4 md:w-5 md:h-5" />
             <h2 className="text-lg md:text-2xl font-black text-white tech-font uppercase tracking-tight italic">已部署模块</h2>
          </div>

          <div className="flex bg-slate-900/40 p-1.5 rounded-2xl border border-slate-800/50 backdrop-blur-sm overflow-x-auto no-scrollbar touch-pan-x gap-1">
            {categories.map((cat) => {
              const Icon = cat.icon;
              const isActive = activeCategory === cat.id;
              return (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`
                    flex items-center gap-2 px-5 md:px-8 py-2.5 rounded-xl text-[10px] md:text-[11px] font-black tech-font uppercase tracking-widest transition-all duration-300 whitespace-nowrap active:scale-95
                    ${isActive 
                      ? 'bg-emerald-500 text-black shadow-[0_10px_20px_rgba(16,185,129,0.25)]' 
                      : 'text-slate-500 hover:text-slate-200 hover:bg-white/5'}
                  `}
                >
                  <Icon size={14} className={isActive ? 'text-black' : 'text-slate-500'} />
                  {cat.label}
                </button>
              );
            })}
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-10">
          {filteredModules.length > 0 ? (
            filteredModules.map(item => <AppCard key={item.id} item={item} onClick={setSelectedItem} />)
          ) : (
            <div className="col-span-full py-16 flex flex-col items-center opacity-30">
              <Loader2 className="w-10 h-10 mb-4 animate-spin text-emerald-500" />
              <p className="tech-font text-[10px] uppercase tracking-widest text-center">当前扇区未发现匹配模块</p>
            </div>
          )}
        </div>
      </main>

      <ActivityTicker />
      {selectedItem && (
        <Modal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

export default App;

export interface SanZiJingVerse {
  id: number;
  text: string[]; // 4句为一组
  pinyin: string[];
  meaning: string;
  history?: string; // 历史典故
}

export const SAN_ZI_JING_DATA: SanZiJingVerse[] = [
  {
    id: 1,
    text: ["人之初", "性本善", "性相近", "习相远"],
    pinyin: ["rén zhī chū", "xìng běn shàn", "xìng xiāng jìn", "xí xiāng yuǎn"],
    meaning: "人生下来的时候，本性都是善良的。这种善良的本性大家都很相近，只是在成长过程中，由于学习和环境的影响，差距才变得越来越大。",
    history: "孟子性善论：这是儒家思想的核心之一，强调后天教育的重要性。"
  },
  {
    id: 2,
    text: ["苟不教", "性乃迁", "教之道", "贵以专"],
    pinyin: ["gǒu bù jiào", "xìng nǎi qiān", "jiào zhī dào", "guì yǐ zhuān"],
    meaning: "如果从小不进行良好的教育，善良的本性就会随环境而改变。教育的方法，最重要的是要专心一致地教导，不能半途而废。",
    history: "孟母三迁：为了给孩子提供良好的教育环境，孟子的母亲曾三次搬家。"
  },
  {
    id: 3,
    text: ["昔孟母", "择邻处", "子不学", "断机杼"],
    pinyin: ["xī mèng mǔ", "zé lín chǔ", "zǐ bù xué", "duàn jī zhù"],
    meaning: "从前孟子的母亲为了让孩子有好的学习环境，曾三次选择邻居搬家。有一次孟子逃学回家，母亲就割断织布机上的布来告诫他。",
    history: "断机教子：通过切断正在织的布，形象地说明学问要靠日积月累，中断就会前功尽弃。"
  },
  {
    id: 4,
    text: ["窦燕山", "有义方", "教五子", "名俱扬"],
    pinyin: ["dòu yàn shān", "yǒu yì fāng", "jiào wǔ zǐ", "míng jù yáng"],
    meaning: "五代时的窦禹钧（燕山人）教子有方，他的五个儿子在父亲的教导下都考中了进士，名声显赫。",
    history: "五子登科：窦燕山的五个儿子相继及第，成为当时教育成功的典范。"
  },
  {
    id: 5,
    text: ["养不教", "父之过", "教不严", "师之惰"],
    pinyin: ["yǎng bù jiào", "fù zhī guò", "jiào bù yán", "shī zhī duò"],
    meaning: "仅仅供养子女而不给予教育，是父亲的过错。老师教导学生如果不严格要求，就是老师在偷懒。",
    history: "传统的家风与师道：强调了家庭教育与学校教育共同的责任。"
  },
  {
    id: 6,
    text: ["子不学", "非所宜", "幼不学", "老何为"],
    pinyin: ["zǐ bù xué", "fēi suǒ yí", "yòu bù xìng", "lǎo hé wéi"],
    meaning: "做子女的不肯勤奋学习，是很不应该的。如果幼年时不肯努力学习，等到年纪大了，还能有什么作为呢？",
    history: "少壮不努力，老大徒伤悲：这是对后辈最深切的劝勉。"
  }
];

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, RotateCcw, BookOpen, 
  Volume2, VolumeX, Info, ChevronRight, 
  Settings, Languages, Sparkles, ScrollText, 
  History, Bookmark, ArrowDownCircle
} from 'lucide-react';
import { SAN_ZI_JING_DATA, SanZiJingVerse } from '../lib/sanzijingData';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    return Number(localStorage.getItem('szj_progress') || 0);
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [showMeaning, setShowMeaning] = useState<SanZiJingVerse | null>(null);
  const [autoScroll, setAutoScroll] = useState(true);
  const [playbackRate, setPlaybackRate] = useState(0.8);

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<{ [key: number]: HTMLDivElement | null }>({});

  // TTS 逻辑
  const speak = useCallback((text: string) => {
    if (!('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;

    utterance.onend = () => {
      if (isPlaying && currentIndex < SAN_ZI_JING_DATA.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        setIsPlaying(false);
      }
    };

    window.speechSynthesis.speak(utterance);
  }, [isPlaying, currentIndex, playbackRate]);

  useEffect(() => {
    if (isPlaying) {
      const verse = SAN_ZI_JING_DATA[currentIndex];
      speak(verse.text.join('，'));
    }

    // 保存进度
    localStorage.setItem('szj_progress', currentIndex.toString());

    // 自动滚动
    if (autoScroll && verseRefs.current[currentIndex]) {
      verseRefs.current[currentIndex]?.scrollIntoView({
        behavior: 'smooth',
        block: 'center'
      });
    }
  }, [currentIndex, isPlaying, autoScroll, speak]);

  const togglePlay = () => {
    if (isPlaying) {
      window.speechSynthesis.cancel();
      setIsPlaying(false);
    } else {
      setIsPlaying(true);
    }
  };

  const handleReset = () => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setCurrentIndex(0);
  };

  return (
    <div className="fixed inset-0 z-50 bg-[#fdfbf7] flex flex-col font-serif text-[#2c3e50] overflow-hidden select-none">
      {/* 宣纸纹理背景 */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      {/* 顶部导航 */}
      <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-20 shrink-0 pt-[env(safe-area-inset-top)]">
        <div className="flex items-center gap-3 md:gap-5">
          <div className="w-10 h-10 md:w-12 md:h-12 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg">
            <ScrollText className="w-5 h-5 md:w-7 md:h-7" />
          </div>
          <div>
            <h1 className="text-base md:text-2xl font-black tracking-tight text-[#2c3e50]">三字经 <span className="text-[9px] bg-[#c0392b]/10 text-[#c0392b] px-2 py-0.5 rounded-full ml-2">蒙学经典</span></h1>
            <p className="text-[8px] md:text-[9px] text-slate-400 font-bold uppercase tracking-[0.3em] flex items-center gap-1">
              Classic of Three Characters
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setShowPinyin(!showPinyin)}
            className={`p-2.5 rounded-full transition-all border ${showPinyin ? 'bg-[#c0392b] text-white border-[#c0392b]' : 'bg-white text-slate-400 border-slate-200'}`}
            title="拼音切换"
          >
            <Languages size={18} />
          </button>
          <button 
            onClick={onClose} 
            className="p-2.5 bg-[#f3efe6] hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-full transition-all"
          >
            <X size={20}/>
          </button>
        </div>
      </header>

      {/* 主体卷轴区 */}
      <main className="flex-1 overflow-y-auto no-scrollbar p-4 md:p-10 relative z-10 space-y-12 pb-40">
        <div className="max-w-3xl mx-auto">
          {SAN_ZI_JING_DATA.map((verse, index) => {
            const isActive = currentIndex === index;
            return (
              <div 
                key={verse.id}
                ref={el => verseRefs.current[index] = el}
                onClick={() => {
                  setCurrentIndex(index);
                  if(!isPlaying) speak(verse.text.join('，'));
                }}
                className={`
                  group relative mb-12 p-8 md:p-12 rounded-[2rem] border-2 transition-all duration-700 cursor-pointer
                  ${isActive 
                    ? 'bg-white border-[#c0392b] shadow-[0_20px_50px_rgba(192,57,43,0.15)] scale-[1.02]' 
                    : 'bg-transparent border-transparent hover:border-[#e0d7c6]'}
                `}
              >
                {/* 活跃状态标识 */}
                {isActive && (
                  <div className="absolute -left-4 top-1/2 -translate-y-1/2 w-1.5 h-12 bg-[#c0392b] rounded-full animate-pulse"></div>
                )}

                <div className="flex flex-wrap justify-center gap-x-12 gap-y-10 md:gap-x-20">
                  {verse.text.map((t, tidx) => (
                    <div key={tidx} className="flex flex-col items-center">
                      {showPinyin && (
                        <span className={`text-[10px] md:text-sm font-mono mb-2 tracking-widest transition-colors duration-500 ${isActive ? 'text-[#c0392b]' : 'text-slate-400 opacity-60'}`}>
                          {verse.pinyin[tidx]}
                        </span>
                      )}
                      <div className="flex">
                        {t.split('').map((char, charIdx) => (
                          <span 
                            key={charIdx} 
                            className={`
                              text-4xl md:text-6xl font-black tracking-widest leading-none transition-all duration-500
                              ${isActive ? 'text-[#2c3e50] transform translate-y-[-2px]' : 'text-slate-300'}
                            `}
                            style={{ 
                              textShadow: isActive ? '2px 2px 0px rgba(0,0,0,0.05)' : 'none',
                              transitionDelay: `${charIdx * 100}ms`
                            }}
                          >
                            {char}
                          </span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>

                {/* 交互按钮 */}
                <div className={`absolute bottom-4 right-8 flex gap-4 transition-opacity duration-500 ${isActive ? 'opacity-100' : 'opacity-0 group-hover:opacity-40'}`}>
                   <button 
                    onClick={(e) => { e.stopPropagation(); setShowMeaning(verse); }}
                    className="p-2 text-[#c0392b] hover:scale-110 transition-transform"
                   >
                     <Info size={20} />
                   </button>
                   <button className="p-2 text-slate-400 hover:text-[#c0392b] transition-colors">
                     <Bookmark size={20} />
                   </button>
                </div>
              </div>
            );
          })}
        </div>
      </main>

      {/* 底部控制台 */}
      <footer className="fixed bottom-0 left-0 w-full bg-white/90 backdrop-blur-xl border-t border-[#e0d7c6] p-6 md:p-8 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
        <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6">

          <div className="flex items-center gap-6">
            <button 
              onClick={handleReset}
              className="p-3 text-slate-400 hover:text-[#c0392b] transition-colors"
              title="重新开始"
            >
              <RotateCcw size={24} />
            </button>

            <button 
              onClick={togglePlay}
              className="w-16 h-16 md:w-20 md:h-20 bg-[#c0392b] text-white rounded-full flex items-center justify-center shadow-xl hover:scale-105 active:scale-95 transition-all group"
            >
              {isPlaying ? <Pause size={32} fill="white" /> : <Play size={32} className="ml-1" fill="white" />}
            </button>

            <div className="flex flex-col gap-1">
              <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">学习进度</span>
              <div className="text-xl font-black italic text-[#2c3e50]">
                {currentIndex + 1} <span className="text-sm opacity-30">/ {SAN_ZI_JING_DATA.length}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8 bg-[#f3efe6]/50 px-6 py-3 rounded-2xl border border-[#e0d7c6]/50">
