      <main 
        ref={scrollRef}
        className={`flex-1 overflow-auto no-scrollbar p-6 md:p-20 relative z-10 transition-all duration-1000 ${isVertical ? 'writing-vertical' : ''}`}
        style={{ writingMode: isVertical ? 'vertical-rl' : 'horizontal-tb' }}
      >
