          {SAN_ZI_JING_DATA.map((verse) => (
            <div 
              key={verse.id}
              onClick={() => setActiveVerse(verse)}
              className={`relative cursor-pointer transition-all duration-500 ${activeVerse?.id === verse.id ? 'scale-105' : 'opacity-60 hover:opacity-100'}`}
            >
