      )}

      {/* 底部控制台 */}
      <footer className="bg-white/90 backdrop-blur-xl border-t border-[#e0d7c6] p-6 md:p-8 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
