          <div className="flex items-center gap-6">
            <button onClick={() => setPlaybackRate(playbackRate === 0.8 ? 1.0 : 0.8)} className="p-3 text-slate-400 hover:text-[#c0392b] transition-colors font-black text-xs">
              {playbackRate}x
            </button>
            <button 
              onClick={handlePlay}
              className="w-16 h-16 md:w-20 md:h-20 bg-[#c0392b] text-white rounded-full flex items-center justify-center shadow-xl hover:scale-105 active:scale-95 transition-all"
            >
              {isPlaying ? <Pause size={32} fill="white" /> : <Play size={32} className="ml-1" fill="white" />}
            </button>
            <button onClick={startRecording} className={`p-4 rounded-full transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-400'}`}>
              <Mic size={24} />
            </button>
          </div>

          <div className="flex items-center gap-4">
            {score !== null && (
              <div className="bg-emerald-50 border border-emerald-100 px-4 py-2 rounded-xl flex items-center gap-2">
                <Trophy size={16} className="text-emerald-500" />
                <span className="text-sm font-black text-emerald-700">评测分: {score}</span>
              </div>
            )}
            <button onClick={() => activeVerse && setActiveVerse(activeVerse)} className="flex items-center gap-2 px-6 py-3 bg-[#2c3e50] text-white rounded-full font-black text-xs uppercase tracking-widest">
              <Languages size={14} /> 译文解析
            </button>
          </div>
        </div>
      </footer>

      {/* 内容解析侧边栏 */}
      <AnimatePresence>
        {activeVerse && (
          <motion.div 
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            className="fixed inset-y-0 right-0 w-full md:w-[450px] bg-white z-[110] shadow-2xl flex flex-col border-l border-[#e0d7c6]"
          >
            <div className="p-8 flex-1 overflow-y-auto no-scrollbar">
              <button onClick={() => setActiveVerse(null)} className="mb-10 p-2 bg-slate-50 rounded-full text-slate-400"><X /></button>

              <div className="text-4xl font-black text-[#c0392b] mb-4 tracking-widest">{activeVerse.text}</div>
              <div className="text-sm font-mono text-slate-400 mb-10">{activeVerse.pinyin.join(' ')}</div>

              <section className="mb-10">
                <h4 className="text-[10px] font-black uppercase text-slate-300 tracking-[0.3em] mb-4">现代译文</h4>
                <p className="text-lg text-slate-600 leading-relaxed italic font-medium">“{activeVerse.meaning}”</p>
              </section>

              <section className="bg-[#fdfbf7] p-8 rounded-[2rem] border border-[#e0d7c6]">
                <div className="flex items-center gap-2 mb-4">
                  <History size={16} className="text-[#c0392b]" />
                  <h4 className="text-sm font-black text-[#2c3e50]">{activeVerse.allusion.title}</h4>
                </div>
                <p className="text-sm text-slate-500 leading-relaxed mb-4">{activeVerse.allusion.content}</p>
                <div className="text-[10px] text-slate-300 font-bold uppercase">— 出处: {activeVerse.allusion.source}</div>
              </section>

              <button className="w-full mt-10 py-5 bg-[#c0392b] text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3">
                <Share2 size={16} /> 生成分享海报
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .writing-vertical {
          padding-top: 10vh;
          height: 100%;
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        @keyframes pulse {
          0% { transform: scale(1); opacity: 1; }
          50% { transform: scale(1.1); opacity: 0.8; }
          100% { transform: scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;

