  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsPlaying(false);
    setCurrentCharIdx(-1);
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    const verse = SAN_ZI_JING_DATA[index];
    const textToRead = verse.chars.join('');
    const utterance = new SpeechSynthesisUtterance(textToRead);

    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;
    utterance.pitch = 1.0;
    utteranceRef.current = utterance;

    // 毫秒级同步核心：监听边界事件
    utterance.onboundary = (event) => {
      if (event.name === 'word' || event.name === 'char') {
        setCurrentCharIdx(event.charIndex);
      }
    };

    utterance.onend = () => {
      if (isPlaying) {
        if (index < SAN_ZI_JING_DATA.length - 1) {
          const next = index + 1;
          setCurrentVerseIdx(next);
          // 使用短延迟确保状态更新平滑
          setTimeout(() => playVerse(next), 400);
        } else {
          // 播放完毕逻辑
          setIsPlaying(false);
          setCurrentCharIdx(-1);
          // 增加积分
          const newPoints = points + 50;
          setPoints(newPoints);
          localStorage.setItem('szj_points', String(newPoints));
        }
      }
    };

    window.speechSynthesis.speak(utterance);

